/* ============================================
   SHARED STYLES — Niche CSS Hacks
   Recording-optimized: full viewport, centered
   ============================================ */

@import url('https://fonts.googleapis.com/css2?family=Geist+Mono:wght@400;500;600;700&family=Outfit:wght@300;400;500;600;700;800&display=swap');

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg: #050506;
  --surface: #0f0f12;
  --surface-2: #18181c;
  --surface-3: #222227;
  --border: #2a2a2f;
  --border-light: #3a3a40;
  --text: #eaeaed;
  --text-2: #9a9aa3;
  --text-3: #5a5a64;
  --mint: #34d399;
  --mint-dim: #34d39918;
  --rose: #fb7185;
  --rose-dim: #fb718518;
  --violet: #a78bfa;
  --violet-dim: #a78bfa18;
  --amber: #fbbf24;
  --sky: #38bdf8;
  --radius: 16px;
  --radius-sm: 10px;
  --font-display: 'Outfit', -apple-system, sans-serif;
  --font-body: 'Outfit', -apple-system, sans-serif;
  --font-mono: 'Geist Mono', monospace;
  color-scheme: dark;
}

html, body {
  height: 100%;
  overflow: hidden;
}

body {
  font-family: var(--font-body);
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

::selection {
  background: var(--mint);
  color: #050506;
}


/* ============================================
   PAGE LAYOUT
   ============================================ */

main {
  max-width: 720px;
  width: 100%;
  padding: 32px 40px;
  display: flex;
  flex-direction: column;
  gap: 28px;
}


/* ============================================
   HERO — Tag, title, description
   ============================================ */

.hero {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.tag {
  display: inline-flex;
  align-self: flex-start;
  font-family: var(--font-mono);
  font-size: 0.85rem;
  font-weight: 500;
  padding: 5px 14px;
  border-radius: 8px;
  margin-bottom: 4px;
  letter-spacing: -0.01em;
}

.tag-mint   { background: var(--mint-dim);   color: var(--mint);   border: 1px solid #34d39930; }
.tag-rose   { background: var(--rose-dim);   color: var(--rose);   border: 1px solid #fb718530; }
.tag-violet { background: var(--violet-dim); color: var(--violet); border: 1px solid #a78bfa30; }

.hero h1 {
  font-family: var(--font-display);
  font-size: clamp(2rem, 5vw, 2.8rem);
  font-weight: 800;
  letter-spacing: -0.035em;
  line-height: 1.08;
  color: #fff;
}

.hero .desc {
  font-size: 1rem;
  font-weight: 300;
  color: var(--text-2);
  line-height: 1.55;
  max-width: 580px;
}


/* ============================================
   DEMO AREA
   ============================================ */

.demo {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 16px;
}


/* ============================================
   COMPARISON LAYOUT (side by side)
   ============================================ */

.comparison {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0;
  width: 100%;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
}

.side {
  padding: 32px 28px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 16px;
}

.side + .side {
  border-left: 1px solid var(--border);
}

.side-label {
  display: flex;
  align-items: center;
  gap: 7px;
  font-size: 0.8rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--text-3);
}

.dot { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }
.dot-red   { background: var(--rose); }
.dot-green { background: var(--mint); }


/* ============================================
   TOGGLE SWITCH
   ============================================ */

.toggle {
  position: relative;
  display: inline-flex;
  align-items: center;
  gap: 12px;
  cursor: pointer;
  font-size: 0.9rem;
  color: var(--text-2);
  user-select: none;
}

.toggle input { position: absolute; opacity: 0; pointer-events: none; }

.toggle-track {
  position: relative;
  width: 48px;
  height: 26px;
  background: var(--border);
  border-radius: 999px;
  transition: background 0.25s;
  flex-shrink: 0;
}

.toggle-track::after {
  content: '';
  position: absolute;
  top: 3px;
  left: 3px;
  width: 20px;
  height: 20px;
  background: var(--text);
  border-radius: 50%;
  transition: translate 0.25s cubic-bezier(.4,.0,.2,1);
}

.toggle input:checked + .toggle-track {
  background: var(--mint);
}

.toggle input:checked + .toggle-track::after {
  translate: 22px 0;
}


/* ============================================
   CODE BLOCK + COPY BUTTON
   ============================================ */

.code-block {
  position: relative;
  width: 100%;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  overflow: hidden;
}

.code-block pre {
  margin: 0;
  padding: 20px 24px;
  overflow-x: auto;
  scrollbar-width: thin;
  scrollbar-color: var(--border) transparent;
  background: var(--surface) !important;
}

.code-block pre[class*="language-"] {
  background: var(--surface) !important;
}

.code-block code,
.code-block code[class*="language-"] {
  font-family: var(--font-mono);
  font-size: 0.8rem;
  color: var(--text-2);
  line-height: 1.85;
  white-space: pre;
  text-shadow: none;
  background: none;
}


/* ============================================
   SYNTAX HIGHLIGHTING (Prism overrides)
   ============================================ */

.token.comment,
.token.prolog,
.token.doctype,
.token.cdata {
  color: var(--text-3);
  font-style: italic;
}

.token.punctuation {
  color: #6b6b76;
}

.token.selector,
.token.tag {
  color: var(--mint);
}

.token.property,
.token.constant,
.token.symbol {
  color: var(--text);
}

.token.atrule,
.token.keyword,
.token.at-rule,
.token.rule {
  color: var(--rose);
}

.token.attr-value,
.token.string,
.token.char,
.token.builtin {
  color: var(--violet);
}

.token.number,
.token.unit {
  color: var(--amber);
}

.token.function,
.token.class-name {
  color: var(--sky);
}

.token.attr-name {
  color: var(--violet);
}

.token.operator {
  color: var(--rose);
}

.token.important,
.token.bold {
  font-weight: 600;
}

.token.entity {
  cursor: help;
}

.copy-btn {
  position: absolute;
  top: 12px;
  right: 14px;
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 5px 12px;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--surface-2);
  color: var(--text-3);
  font-family: var(--font-body);
  font-size: 0.72rem;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.2s, color 0.2s, border-color 0.2s;
  z-index: 2;
  user-select: none;
}

.copy-btn:hover {
  background: var(--surface-3);
  color: var(--text);
  border-color: var(--border-light);
}

.copy-btn.copied {
  color: var(--mint);
  border-color: var(--mint);
}

.copy-btn svg {
  width: 14px;
  height: 14px;
  flex-shrink: 0;
}

.copy-btn .icon-check { display: none; }
.copy-btn.copied .icon-copy { display: none; }
.copy-btn.copied .icon-check { display: block; }



/* ============================================
   SHARED UTILITY
   ============================================ */

.demo-input {
  width: 100%;
  max-width: 300px;
  padding: 12px 16px;
  border-radius: 8px;
  background: var(--surface-2);
  border: 1.5px solid var(--border);
  color: var(--text);
  font-family: var(--font-body);
  font-size: 0.95rem;
  outline: none;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.demo-input:focus {
  border-color: var(--mint);
  box-shadow: 0 0 0 3px var(--mint-dim);
}

