.has-card {
    width: 100%;
    padding: 32px;
    border-radius: var(--radius);
    background: var(--surface);
    border: 1px solid var(--border);
    transition: background 0.5s, border-color 0.5s, box-shadow 0.5s;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 24px;
  }

  .icon-row {
    display: flex;
    gap: 14px;
    transition: gap 0.5s;
  }

  .icon-box {
    width: 48px;
    height: 48px;
    border-radius: 12px;
    background: var(--surface-2);
    border: 1px solid var(--border);
    transition: all 0.4s cubic-bezier(.4,0,.2,1);
  }

  .has-text {
    font-size: 0.92rem;
    color: var(--text-2);
    text-align: center;
    max-width: 400px;
    transition: color 0.5s;
  }

  .has-card:has(input:checked) {
    background: var(--mint);
    border-color: transparent;
    box-shadow: 0 0 80px #34d39950;
  }

  .has-card:has(input:checked) .icon-box {
    background: #050506;
    border-color: transparent;
    scale: 1.2;
  }

  .has-card:has(input:checked) .icon-box:nth-child(1) { rotate: -15deg; }
  .has-card:has(input:checked) .icon-box:nth-child(2) { rotate: 8deg; }
  .has-card:has(input:checked) .icon-box:nth-child(3) { rotate: -5deg; }
  .has-card:has(input:checked) .icon-row { gap: 22px; }
  .has-card:has(input:checked) .has-text { color: #052e16; }
  .has-card:has(input:checked) .toggle-track { background: #052e16; }
  .has-card:has(input:checked) .toggle-track::after { background: var(--mint); }
  .has-card:has(input:checked) .toggle { color: #052e16; }
